function MemorySlide({ memory, index, total }: any) {
  const ref = useRef(null);
  const isInView = useInView(ref, { amount: 0.6 });

  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"],
  });

  const imageScale = useTransform(
    scrollYProgress,
    [0, 0.5, 1],
    [1.08, 1, 1.08],
  );
  const imageY = useTransform(scrollYProgress, [0, 0.5, 1], [40, 0, -40]);
  const contentY = useTransform(scrollYProgress, [0, 0.5, 1], [60, 0, -60]);
  const contentOpacity = useTransform(
    scrollYProgress,
    [0, 0.2, 0.5, 0.8, 1],
    [0.2, 0.7, 1, 0.7, 0.2],
  );

  return (
    <section ref={ref} className="memory-slide">
      <motion.div
        className="memory-slide-inner"
        animate={{
          opacity: isInView ? 1 : 0.3,
          scale: isInView ? 1 : 0.95,
        }}
        transition={{ duration: 0.7 }}
      >
        <div className="memory-media">
          <motion.div style={{ scale: imageScale, y: imageY }}>
            <Image src={memory.image} alt="" fill className="memory-image" />
          </motion.div>
          <div className="memory-overlay" />
        </div>

        <motion.div
          className="memory-content"
          style={{ y: contentY, opacity: contentOpacity }}
        >
          <p className="memory-kicker">
            {memory.label} • {index + 1}/{total}
          </p>

          {index === 0 ? (
            <>
              <h1>Happy 30th Birthday, Naawal</h1>
              <p className="opening-text">{memory.text}</p>
            </>
          ) : (
            <p className="memory-text">{memory.text}</p>
          )}
        </motion.div>
      </motion.div>
    </section>
  );
}

export default function HomePage() {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [userInteracted, setUserInteracted] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  // AUTO SLIDE
  useEffect(() => {
    if (userInteracted) return;

    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1 >= memories.length ? 0 : prev + 1));
    }, AUTO_DURATION);

    return () => clearInterval(interval);
  }, [userInteracted]);

  // SCROLL TO SLIDE
  useEffect(() => {
    const slides = containerRef.current?.querySelectorAll(".memory-slide");
    const target = slides?.[currentIndex] as HTMLElement;

    target?.scrollIntoView({ behavior: "smooth" });
  }, [currentIndex]);

  // STOP AUTO IF USER INTERACTS
  useEffect(() => {
    const stop = () => setUserInteracted(true);

    window.addEventListener("wheel", stop);
    window.addEventListener("touchstart", stop);
    window.addEventListener("keydown", stop);

    return () => {
      window.removeEventListener("wheel", stop);
      window.removeEventListener("touchstart", stop);
      window.removeEventListener("keydown", stop);
    };
  }, []);

  // MUSIC
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const tryPlay = async () => {
      try {
        await audio.play();
        setIsPlaying(true);
      } catch {}
    };

    tryPlay();
  }, []);

  const toggleAudio = async () => {
    const audio = audioRef.current;
    if (!audio) return;

    if (audio.paused) {
      await audio.play();
      setIsPlaying(true);
    } else {
      audio.pause();
      setIsPlaying(false);
    }
  };

  const year = useMemo(() => new Date().getFullYear(), []);

  return (
    <main className="vertical-carousel-page">
      <audio ref={audioRef} loop>
        <source
          src="/music/happy-birthday-simi-adekunle.mp3"
          type="audio/mpeg"
        />
      </audio>

      <button className="music-button" onClick={toggleAudio}>
        <span>{isPlaying ? "Now playing" : "Tap to play"}</span>
        <strong>Happy Birthday 🎵</strong>
      </button>

      <div className="slides-shell" ref={containerRef}>
        {memories.map((m, i) => (
          <MemorySlide
            key={m.image}
            memory={m}
            index={i}
            total={memories.length}
          />
        ))}
      </div>

      <footer className="end-cap">
        <p>Made with love, style, and the right amount of extra.</p>
        <span>{year}</span>
      </footer>
    </main>
  );
}
